const BASE_URL = "https://api.hookdeck.com/2025-07-01";

async function request(endpoint, options = {}) {
  const url = `${BASE_URL}${endpoint}`;
  const response = await fetch(url, {
    ...options,
    headers: {
      "Authorization": `Bearer ${HOOKDECK_API_KEY}`,
      "Content-Type": "application/json",
      ...options.headers,
    },
  });

  const text = await response.text();
  let json;
  try {
    json = JSON.parse(text);
  } catch (e) {
    throw new Error(`Failed to parse JSON response from ${endpoint}: ${text}`);
  }

  if (!response.ok) {
    throw new Error(`HTTP Error ${response.status} from ${endpoint}: ${JSON.stringify(json)}`);
  }

  return json;
}

