    console.log(`Destination ID = ${destination.id}`);

    console.log("3. Setting up Transformation...");
    const transformation = await getOrCreateTransformation(trfName);
    console.log(`Transformation ID = ${transformation.id}`);

    console.log("4. Setting up Connection...");
    const connection = await getOrCreateConnection(connName, source.id, destination.id, transformation.id);
    console.log(`Connection ID = ${connection.id}`);

    console.log("\nPipeline setup completed successfully!");
    console.log(`Source Name: ${srcName}`);
    console.log(`Destination Name: ${dstName}`);
    console.log(`Connection ID: ${connection.id}`);
    console.log(`Transformation ID: ${transformation.id}`);
    console.log(`Source URL to send webhooks to: ${source.url}`);

  } catch (error) {
    console.error("Pipeline creation failed:", error);
    process.exit(1);
  }
}

main();

